public class Main {
    public static void main(String[] args) {
        try {
            // 例外をスローする可能性があるメソッドを呼び出す
            divide(10, 0);
        } catch (ArithmeticException e) {
            // 例外をキャッチしてメッセージを出力する
            System.out.println("Cannot divide by zero");
            // 出力: Cannot divide by zero
        }
    }

    // 引数bが0の場合にArithmeticExceptionをスローするメソッド
    public static int divide(int a, int b) throws ArithmeticException {
        if (b == 0) {
            throw new ArithmeticException();
        }
        return a / b;
    }
}

public class Main {
    public static void main(String[] args) {
        try {
            // 例外をスローする可能性があるメソッドを呼び出す
            validateNumber(-10);
        } catch (InvalidNumberException e) {
            // 例外をキャッチしてメッセージを出力する
            System.out.println(e.getMessage());
            // 出力: Invalid number: -10
        }
    }

    // 引数numが0未満の場合にInvalidNumberExceptionをスローするメソッド
    public static void validateNumber(int num) throws InvalidNumberException {
        if (num < 0) {
            throw new InvalidNumberException("Invalid number: " + num);
        }
    }
}

